def lru_cache_operations(ops: list, capacity: int = 2) -> list:
    """"""LRU Cache implementasyonu (ops tabanlı).

    ops: [('LRUCache', capacity), ('put', key, val), ('get', key), ...]

    Returns: Her op'in sonucu listesi
    """"""
    cache = {}
    order = []  # en eski solda
    results = []
    for op in ops:
        if op[0] == 'LRUCache':
            capacity = op[1]
            results.append(None)
        elif op[0] == 'put':
            key, val = op[1], op[2]
            if key in cache:
                order.remove(key)
            elif len(cache) >= capacity:
                oldest = order.pop(0)
                del cache[oldest]
            cache[key] = val
            order.append(key)
            results.append(None)
        elif op[0] == 'get':
            key = op[1]
            if key in cache:
                order.remove(key)
                order.append(key)
                results.append(cache[key])
            else:
                results.append(-1)
    return results

