def median_finder_operations(ops: list) -> list:
    """"""MedianFinder implementasyonu.

    ops: [('MedianFinder',), ('addNum', num), ('findMedian',), ...]

    Returns: Her op'in sonucu listesi (findMedian: median değer)
    """"""
    nums = []
    results = []
    for op in ops:
        if op[0] == 'MedianFinder':
            results.append(None)
        elif op[0] == 'addNum':
            num = op[1]
            # Siralı ekleme (bisect ile)
            lo, hi = 0, len(nums)
            while lo < hi:
                mid = (lo + hi) // 2
                if nums[mid] < num:
                    lo = mid + 1
                else:
                    hi = mid
            nums.insert(lo, num)
            results.append(None)
        elif op[0] == 'findMedian':
            n = len(nums)
            if n % 2 == 1:
                results.append(float(nums[n // 2]))
            else:
                results.append((nums[n // 2 - 1] + nums[n // 2]) / 2.0)
    return results

