def min_stack_operations(ops: list) -> list:
    """"""MinStack implementasyonu.

    ops: [('MinStack',), ('push', val), ('pop',), ('top',), ('getMin',), ...]

    Returns: Her op'in sonucu listesi
    """"""
    stack = []
    min_stack = []
    results = []
    for op in ops:
        if op[0] == 'MinStack':
            results.append(None)
        elif op[0] == 'push':
            val = op[1]
            stack.append(val)
            if not min_stack or val <= min_stack[-1]:
                min_stack.append(val)
            results.append(None)
        elif op[0] == 'pop':
            if stack:
                val = stack.pop()
                if val == min_stack[-1]:
                    min_stack.pop()
                results.append(None)
        elif op[0] == 'top':
            results.append(stack[-1] if stack else None)
        elif op[0] == 'getMin':
            results.append(min_stack[-1] if min_stack else None)
    return results

