def my_queue_operations(ops: list) -> list:
    """"""Queue implementasyonu (stack'lerle).

    ops: [('MyQueue',), ('push', x), ('pop',), ('peek',), ('empty',), ...]
    """"""
    in_stack = []
    out_stack = []
    results = []
    for op in ops:
        if op[0] == 'MyQueue':
            results.append(None)
        elif op[0] == 'push':
            in_stack.append(op[1])
            results.append(None)
        elif op[0] == 'pop':
            if not out_stack:
                while in_stack:
                    out_stack.append(in_stack.pop())
            results.append(out_stack.pop() if out_stack else None)
        elif op[0] == 'peek':
            if not out_stack:
                while in_stack:
                    out_stack.append(in_stack.pop())
            results.append(out_stack[-1] if out_stack else None)
        elif op[0] == 'empty':
            results.append(len(in_stack) == 0 and len(out_stack) == 0)
    return results

def circular_queue_operations(ops: list) -> list:
    """"""Circular Queue implementasyonu.

    ops: [('CircularQueue', k), ('enQueue', val), ('deQueue',), ('Front',), ('Rear',), ('isEmpty',), ('isFull',), ...]
    """"""
    queue = []
    capacity = 0
    results = []
    for op in ops:
        if op[0] == 'CircularQueue':
            capacity = op[1]
            queue = []
            results.append(None)
        elif op[0] == 'enQueue':
            if len(queue) < capacity:
                queue.append(op[1])
                results.append(True)
            else:
                results.append(False)
        elif op[0] == 'deQueue':
            if queue:
                queue.pop(0)
                results.append(True)
            else:
                results.append(False)
        elif op[0] == 'Front':
            results.append(queue[0] if queue else -1)
        elif op[0] == 'Rear':
            results.append(queue[-1] if queue else -1)
        elif op[0] == 'isEmpty':
            results.append(len(queue) == 0)
        elif op[0] == 'isFull':
            results.append(len(queue) == capacity)
    return results
